// ═══════════════════════════════════════════════════════════
// Ajusta formato para Google Docs — Code Node (corrigido)
// ═══════════════════════════════════════════════════════════

// ─── 1. Leitura de inputs ───
const transcription = $('Transcreve com Google Gemini').first().json?.content?.parts?.[0]?.text || '';
const agentOutput = $input.first().json.output || {};
const summary = agentOutput.summary_text || '';
const docId = agentOutput.doc_id || '';

// ─── 2. Validação (fail-fast com mensagem clara) ───
if (!docId) {
  throw new Error('[meet2docs] doc_id ausente. O agente nao criou o documento. Verifique o node Criar Documento de Resumo e o output parser.');
}
if (!transcription && !summary) {
  throw new Error('[meet2docs] Transcricao e resumo ambos vazios. Nada a gravar.');
}

// ─── 3. Monta documento: transcrição em cima, resumo embaixo ───
const HEADER = '🎙 TRANSCRIÇÃO COMPLETA\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
const SEP    = '\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n📋 RESUMO\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

const fullText = HEADER
  + (transcription || '(Transcricao nao disponivel)')
  + SEP
  + (summary || '(Resumo nao disponivel)');

let text = fullText.replace(/\r\n/g, '\n');

// ─── 4. Parser de estilos (bold, italic, bullets) ───
let plainText = '';
const styles  = [];
const bullets = [];
let cursor = 1;

const lines = text.split('\n');

for (let line of lines) {
  if (!line.trim()) {
    plainText += '\n';
    cursor++;
    continue;
  }

  const lineStartCursor = cursor;

  let isBullet = false;
  const trimmed = line.trim();
  if (trimmed.startsWith('✦') || trimmed.startsWith('✓') || trimmed.startsWith('-')) {
    isBullet = true;
    line = trimmed.substring(1).trim();
  }

  const regex = /(\*\*([^*]+)\*\*|\*([^*]+)\*|([^*]+))/g;
  let match;
  while ((match = regex.exec(line)) !== null) {
    const raw   = match[0];
    const clean = match[2] || match[3] || match[4] || '';
    if (!clean) continue;

    const start = cursor;
    const end   = cursor + clean.length;

    plainText += clean;

    if (raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { bold: true },
        fields: 'bold'
      });
    } else if (raw.startsWith('*') && !raw.startsWith('**')) {
      styles.push({
        range: { startIndex: start, endIndex: end },
        textStyle: { italic: true },
        fields: 'italic'
      });
    }

    cursor = end;
  }

  plainText += '\n';
  cursor++;

  if (isBullet) {
    bullets.push({
      range: {
        startIndex: lineStartCursor,
        endIndex: cursor
      },
      bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
    });
  }
}

// ─── 5. Monta array de requests para documents.batchUpdate ───
const requests = [];

requests.push({
  insertText: {
    endOfSegmentLocation: {},
    text: plainText
  }
});

for (const s of styles) {
  requests.push({
    updateTextStyle: {
      range: s.range,
      textStyle: s.textStyle,
      fields: s.fields
    }
  });
}

for (const b of bullets) {
  requests.push({
    createParagraphBullets: b
  });
}

// ─── 6. Retorna requests + doc_id ───
return [{ json: { requests, doc_id: docId } }];

